import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.C6K0jwmI.js";const _=JSON.parse('{"title":"管理ダッシュボード","description":"","frontmatter":{"title":"管理ダッシュボード"},"headers":[],"relativePath":"tenant/03-dashboard.md","filePath":"tenant/03-dashboard.md"}'),h={name:"tenant/03-dashboard.md"};function o(l,t,i,n,s,b){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="_3-管理ダッシュボード" tabindex="-1">3. 管理ダッシュボード <a class="header-anchor" href="#_3-管理ダッシュボード" aria-label="Permalink to &quot;3. 管理ダッシュボード&quot;">​</a></h1><p>管理ダッシュボードは、店舗運営に必要な設定と確認を行う画面です。ログインしたユーザーのロールに応じて、表示されるタブが変わります。</p><h2 id="画面の基本構成" tabindex="-1">画面の基本構成 <a class="header-anchor" href="#画面の基本構成" aria-label="Permalink to &quot;画面の基本構成&quot;">​</a></h2><table tabindex="0"><thead><tr><th>場所</th><th>内容</th></tr></thead><tbody><tr><td>ヘッダー</td><td>店舗名、店舗切替、ログイン中のユーザー名、パスワード変更</td></tr><tr><td>メインタブ</td><td>メニュー、注文、レポート、店舗設定などの機能切替</td></tr><tr><td>サブタブ</td><td>各機能の中の詳細メニュー</td></tr><tr><td>右下のAIヘルプデスク</td><td>操作で困ったときに質問できるサポートボタン</td></tr></tbody></table><h2 id="ロール別の表示" tabindex="-1">ロール別の表示 <a class="header-anchor" href="#ロール別の表示" aria-label="Permalink to &quot;ロール別の表示&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ロール</th><th>主に表示される内容</th></tr></thead><tbody><tr><td>オーナー</td><td>複数店舗管理、本部機能、契約・決済設定、ユーザー管理</td></tr><tr><td>マネージャー</td><td>担当店舗のメニュー、注文、会計、在庫、シフト、レポート、店舗設定</td></tr><tr><td>スタッフ</td><td>勤怠打刻、マイシフト、希望シフト提出</td></tr></tbody></table><p>表示されないタブがある場合は、権限または所属店舗が不足している可能性があります。</p><h2 id="店舗を切り替える" tabindex="-1">店舗を切り替える <a class="header-anchor" href="#店舗を切り替える" aria-label="Permalink to &quot;店舗を切り替える&quot;">​</a></h2><p>複数店舗に所属している場合は、画面上部の店舗セレクターから操作対象の店舗を選びます。選択した店舗に対して、メニュー、注文、レポートなどの操作が行われます。</p><h2 id="aiヘルプデスクを使う" tabindex="-1">AIヘルプデスクを使う <a class="header-anchor" href="#aiヘルプデスクを使う" aria-label="Permalink to &quot;AIヘルプデスクを使う&quot;">​</a></h2><p>管理画面右下のAIヘルプデスクから、操作方法やエラー時の対応を質問できます。質問するときは、画面名、操作内容、表示されたメッセージを一緒に入力すると回答が正確になります。</p><h2 id="操作時の注意" tabindex="-1">操作時の注意 <a class="header-anchor" href="#操作時の注意" aria-label="Permalink to &quot;操作時の注意&quot;">​</a></h2><ul><li>複数店舗を管理している場合は、操作前に選択中の店舗名を確認してください。</li><li>スタッフアカウントでは、店舗運営に必要な一部機能のみ表示されます。</li><li>画面表示が古い場合は、ブラウザの再読み込みを行ってください。</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>タブが表示されない</td><td>権限と所属店舗を確認してください。</td></tr><tr><td>店舗が選べない</td><td>オーナーまたはマネージャーに所属店舗の設定を確認してください。</td></tr><tr><td>読み込みに失敗する</td><td>再読み込みし、改善しない場合はPOSLAサポートへお問い合わせください。</td></tr></tbody></table>',15)])])}const u=a(h,[["render",o]]);export{_ as __pageData,u as default};
